/**
 * Postbuild sitemap script
 * 1. Reads sitemap-0.xml (generated by next-sitemap with correct hreflang via hrefIsAbsolute)
 * 2. Splits URLs into per-locale/per-type sitemap files
 * 3. Deletes sitemap-0.xml and any stale per-locale sitemaps
 * 4. Writes sitemap.xml index pointing to all generated sitemaps
 *
 * Hreflang is generated by next-sitemap.config.cjs (with hrefIsAbsolute: true).
 * This script trusts the hreflang from next-sitemap and only splits the output.
 * Both files share locale config from lib/sitemap-locale-config.cjs.
 *
 * Run after next-sitemap: npm run postbuild
 */

const fs = require('node:fs');
const path = require('node:path');

const {
  SITE_URL,
  LOCALE_TOOLS_BASE,
} = require('../lib/sitemap-locale-config.cjs');

const PUBLIC_DIR = path.join(process.cwd(), 'public');

const XML_HEADER =
  '<?xml version="1.0" encoding="UTF-8"?>\n<urlset xmlns="http://www.sitemaps.org/schemas/sitemap/0.9" xmlns:xhtml="http://www.w3.org/1999/xhtml" xmlns:image="http://www.google.com/schemas/sitemap-image/1.1">';
const XML_FOOTER = '</urlset>';

/** Determine which sitemap file a URL path belongs to */
function categorize(urlPath) {
  for (const [locale, base] of Object.entries(LOCALE_TOOLS_BASE)) {
    if (urlPath === base || urlPath.startsWith(base + '/')) {
      return `sitemap-tools-${locale}.xml`;
    }
  }
  if (urlPath.startsWith('/uslugi')) return 'sitemap-services.xml';
  if (urlPath.startsWith('/edukacja')) return 'sitemap-education.xml';
  if (urlPath.startsWith('/realizacje')) return 'sitemap-projects.xml';
  return 'sitemap-pages.xml';
}

function main() {
  const sitemap0Path = path.join(PUBLIC_DIR, 'sitemap-0.xml');
  if (!fs.existsSync(sitemap0Path)) {
    console.warn('⚠️  sitemap-0.xml not found — skipping split');
    process.exit(0);
  }

  // 1. Parse sitemap-0.xml into individual <url> blocks
  const xml = fs.readFileSync(sitemap0Path, 'utf8');
  const urlBlocks = xml.match(/<url>[\s\S]*?<\/url>/g) || [];

  // 2. Split URL blocks into per-locale/per-type buckets
  const buckets = new Map();
  for (const block of urlBlocks) {
    const locMatch = block.match(/<loc>([^<]+)<\/loc>/);
    if (!locMatch) continue;
    const urlPath = locMatch[1].replace(SITE_URL, '');

    const file = categorize(urlPath);
    if (!buckets.has(file)) buckets.set(file, []);
    buckets.get(file).push(block);
  }

  // 3. Delete ALL old sitemap-*.xml files (except sitemap.xml itself)
  const oldFiles = fs
    .readdirSync(PUBLIC_DIR)
    .filter(f => f.startsWith('sitemap-') && f.endsWith('.xml'));
  for (const f of oldFiles) {
    fs.unlinkSync(path.join(PUBLIC_DIR, f));
  }

  // 4. Write new per-locale/per-type sitemap files
  for (const [file, blocks] of buckets.entries()) {
    const content = [XML_HEADER, ...blocks, XML_FOOTER].join('\n');
    fs.writeFileSync(path.join(PUBLIC_DIR, file), content, 'utf8');
    console.log(`  ✓ ${file} (${blocks.length} URLs)`);
  }

  // 5. Write sitemap index (with <lastmod> per sub-sitemap for efficient Google re-crawling)
  const sitemapFiles = fs
    .readdirSync(PUBLIC_DIR)
    .filter(f => f.startsWith('sitemap-') && f.endsWith('.xml'))
    .sort();

  const entries = sitemapFiles
    .map(f => {
      const content = fs.readFileSync(path.join(PUBLIC_DIR, f), 'utf8');
      const lastmods = [
        ...content.matchAll(/<lastmod>([^<]+)<\/lastmod>/g),
      ].map(m => m[1]);
      const newest = lastmods.sort().pop();
      const lastmodTag = newest ? `<lastmod>${newest}</lastmod>` : '';
      return `<sitemap><loc>${SITE_URL}/${f}</loc>${lastmodTag}</sitemap>`;
    })
    .join('\n');

  const sitemapIndex = [
    '<?xml version="1.0" encoding="UTF-8"?>',
    '<sitemapindex xmlns="http://www.sitemaps.org/schemas/sitemap/0.9">',
    entries,
    '</sitemapindex>',
  ].join('\n');

  fs.writeFileSync(path.join(PUBLIC_DIR, 'sitemap.xml'), sitemapIndex, 'utf8');
  console.log(
    `✓ sitemap.xml index → ${sitemapFiles.length} sitemaps, ${urlBlocks.length} total URLs`,
  );
}

main();
